Step 1 — Create the Workflow File
In your repository, create this folder structure:
.github/
workflows/
security-review.ymlOpen security-review.yml and start with the trigger configuration:
name: AI Security Reviewon:
pull_request:
types: [opened, synchronize]jobs:
security-scan:
runs-on: ubuntu-latest
permissions:
pull-requests: write
contents: readThis tells GitHub to run this workflow every time a pull request is opened or updated with new commits, and grants it permission to comment on the PR.

Step 2 — Get Only the Changed Files
We don’t want to scan the entire repository on every PR — just what actually changed. Add this step:
steps:
- name: Checkout code
uses: actions/checkout@v4
with:
fetch-depth: 0 - name: Get changed files
id: changed-files
run: |
git diff --name-only origin/${{ github.base_ref }} \
origin/${{ github.head_ref }} \
| grep -E '\.(js|ts|jsx|tsx)$' > changed_files.txt || true
echo "count=$(wc -l < changed_files.txt)" >> $GITHUB_OUTPUTThis grabs only the JavaScript and TypeScript files that changed between the base branch and the PR branch, filtering out everything else.

Step 3 — Build the Review Script
Create a new file at .github/scripts/review.js:
const fs = require('fs');const SECURITY_PROMPT = `
You are reviewing a code diff from a pull request for
security vulnerabilities only. Analyze the following changes.For each vulnerability found, respond in this exact format:
SEVERITY: Critical/High/Medium/Low
FILE: filename
ISSUE: one line description
FIX: one line suggested fixIf no vulnerabilities are found, respond with exactly: NONE_FOUNDCode diff to review:
`;async function reviewFiles(filePaths) {
const findings = []; for (const filePath of filePaths) {
if (!filePath.trim()) continue; const code = fs.readFileSync(filePath, 'utf-8');
const result = await callAI(SECURITY_PROMPT + code); if (result.trim() !== 'NONE_FOUND') {
findings.push({ file: filePath, result });
}
} return findings;
}async function callAI(prompt) {
const response = await fetch(process.env.AI_API_ENDPOINT, {
method: 'POST',
headers: {
'Content-Type': 'application/json',
'Authorization': `Bearer ${process.env.AI_API_KEY}`
},
body: JSON.stringify({
model: process.env.AI_MODEL,
max_tokens: 800,
messages: [{ role: 'user', content: prompt }]
})
}); const data = await response.json();
return data.choices ? data.choices[0].message.content : data.content[0].text;
}module.exports = { reviewFiles };This reads each changed file and sends it through a structured security prompt, collecting only the findings that actually matter.

