Step 4 — Wire It Into the Workflow
Back in security-review.yml, add the step that runs this script:
- name: Setup Node
uses: actions/setup-node@v4
with:
node-version: '20' - name: Run security review
id: review
env:
AI_API_KEY: ${{ secrets.AI_API_KEY }}
AI_API_ENDPOINT: ${{ secrets.AI_API_ENDPOINT }}
AI_MODEL: ${{ secrets.AI_MODEL }}
run: |
node .github/scripts/run-review.jsNotice the API key comes from secrets — never hardcoded. You'll add this in your repository settings under Settings → Secrets and variables → Actions.

Step 5 — Post Results as a PR Comment
Findings are useless if nobody sees them. Create .github/scripts/run-review.js:
const fs = require('fs');
const { reviewFiles } = require('./review');async function main() {
const changedFiles = fs.readFileSync('changed_files.txt', 'utf-8')
.split('\n')
.filter(Boolean); if (changedFiles.length === 0) {
console.log('No relevant files changed.');
return;
} const findings = await reviewFiles(changedFiles); if (findings.length === 0) {
console.log('No security issues found.');
fs.writeFileSync('review_result.md', '✅ No security issues found in this PR.');
return;
} let comment = '## 🔍 AI Security Review\n\n';
let hasCritical = false; for (const finding of findings) {
comment += `### ${finding.file}\n\n${finding.result}\n\n---\n\n`;
if (finding.result.includes('SEVERITY: Critical')) {
hasCritical = true;
}
} fs.writeFileSync('review_result.md', comment); if (hasCritical) {
console.error('Critical security issues found. Failing check.');
process.exit(1);
}
}main();This builds a clean markdown report and exits with a failure code if anything critical was found — which is what actually blocks the merge.

